import os

from flask_limiter import Limiter
from flask_limiter.util import get_remote_address


def _read_str_env(name: str) -> str:
    raw_value = os.environ.get(name)
    if raw_value is None:
        return ""
    return str(raw_value).strip()


def _read_optional_str_env(name: str) -> str | None:
    raw_value = os.environ.get(name)
    if raw_value is None:
        return None

    cleaned = str(raw_value).strip()
    return cleaned or None


def _read_storage_uri() -> str:
    raw_value = os.environ.get("RATELIMIT_STORAGE_URI")
    if raw_value is None:
        return "memory://"

    cleaned = raw_value.strip()
    return cleaned if cleaned else "memory://"


def _redis_prerequisite_ok() -> tuple[bool, str]:
    """Return (ok, reason) for limits Redis storage prerequisites."""

    try:
        import redis  # type: ignore[import-not-found]
    except Exception as exc:
        return False, f"redis import failed: {exc.__class__.__name__}: {exc}"

    version = getattr(redis, "__version__", "") or ""
    try:
        major = int(str(version).split(".", 1)[0])
    except Exception:
        major = 0

    if major < 3:
        return False, f"redis python package too old: {version!r}"

    return True, f"redis {version}"


def _build_storage_options(storage_uri: str) -> dict:
    storage_options: dict = {}
    storage_uri_lower = storage_uri.lower()

    is_redis_scheme = storage_uri_lower.startswith(
        ("redis://", "rediss://", "valkey://", "valkeys://")
    )
    if is_redis_scheme:
        storage_options["socket_connect_timeout"] = 2.0
        storage_options["socket_timeout"] = 2.0

    auth_mode = _read_str_env("RATELIMIT_AUTH_MODE").lower()
    if auth_mode != "entra":
        return storage_options

    if not is_redis_scheme:
        return storage_options

    token_scope = _read_optional_str_env("RATELIMIT_REDIS_TOKEN_SCOPE")
    username_override = _read_optional_str_env("RATELIMIT_REDIS_USERNAME")
    username_claim_env = _read_optional_str_env("RATELIMIT_REDIS_USERNAME_CLAIM")

    username_claim = username_claim_env or "oid"

    from utils.redis_entra import EntraRedisCredentialProvider, build_redis_token_scopes

    token_scopes = build_redis_token_scopes(token_scope)

    credential_provider = EntraRedisCredentialProvider(
        scope=token_scopes[0],
        fallback_scopes=token_scopes[1:],
        username=username_override,
        username_claim=username_claim,
    )

    storage_options["credential_provider"] = credential_provider
    return storage_options


# Initialize Limiter object here, but DO NOT associate with app yet
_STORAGE_URI = _read_storage_uri()
_STORAGE_OPTIONS: dict = {}
_STORAGE_FALLBACK_REASON = ""
_REDIS_PREREQ_STATUS = ""

if _STORAGE_URI.lower().startswith(("redis://", "rediss://", "valkey://", "valkeys://")):
    ok, status = _redis_prerequisite_ok()
    _REDIS_PREREQ_STATUS = status
    if not ok:
        _STORAGE_FALLBACK_REASON = status
        _STORAGE_URI = "memory://"

try:
    _STORAGE_OPTIONS = _build_storage_options(_STORAGE_URI)
except Exception:
    if (_read_str_env("RATELIMIT_AUTH_MODE").lower() == "entra") and _STORAGE_URI.lower().startswith(
        ("redis://", "rediss://", "valkey://", "valkeys://")
    ):
        # Keep the app online if Entra auth is misconfigured by falling back to in-memory
        # rate limiting until the infra settings are corrected.
        _STORAGE_FALLBACK_REASON = "Entra credential provider init failed"
        _STORAGE_URI = "memory://"
        _STORAGE_OPTIONS = {}

